import pytest
from source import pascal

def test_pascal_trailing_ones_and_lengths():
    rows = pascal(3)
    assert len(rows) == 3, f"Expected 3 rows, got {len(rows)}"
    for i, row in enumerate(rows):
        expected_len = i + 1
        assert len(row) == expected_len, (
            f"Row {i + 1} length mismatch: expected {expected_len}, got {len(row)}"
        )
        assert row[-1] == 1, (
            f"Row {i + 1} does not end with 1 as expected: {row}"
        )
